  describe('invariant examples', () => {
    it("create then add items then get", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(fieldItemListHandler.create({ list: "test-l", name: "Profile Fields", schema: "Person" }), storage);
      expect(createResult0.variant).toBe("ok");
      let list = createResult0.output["list"];
      let l = list;
      const addItemResult1 = await interpret(fieldItemListHandler.addItem({ list: l, placementId: "fp-name", position: 0 }), storage);
      expect(addItemResult1.variant).toBe("ok");
      list = addItemResult1.output["list"];
      const addItemResult2 = await interpret(fieldItemListHandler.addItem({ list: l, placementId: "fp-email" }), storage);
      expect(addItemResult2.variant).toBe("ok");
      list = addItemResult2.output["list"];
      const thenResult0 = await interpret(fieldItemListHandler.get({ list: l }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("nest and collapse", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(fieldItemListHandler.create({ list: "test-parent", name: "Contact", schema: "Person" }), storage);
      expect(createResult0.variant).toBe("ok");
      let list = createResult0.output["list"];
      let parent = list;
      const createResult1 = await interpret(fieldItemListHandler.create({ list: "test-child", name: "Address", schema: "Person" }), storage);
      expect(createResult1.variant).toBe("ok");
      list = createResult1.output["list"];
      let child = list;
      const nestResult2 = await interpret(fieldItemListHandler.nest({ list: child, parent: parent }), storage);
      expect(nestResult2.variant).toBe("ok");
      list = nestResult2.output["list"];
      const thenResult0 = await interpret(fieldItemListHandler.setCollapsed({ list: child, collapsed: true }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: lists have names', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ list: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), schema: fc.string() }) }),
              fc.record({ action: fc.constant('addItem'), input: fc.record({ list: fc.string(), placementId: fc.string({ minLength: 1, maxLength: 50 }), position: fc.string() }) }),
              fc.record({ action: fc.constant('removeItem'), input: fc.record({ list: fc.string(), placementId: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('reorder'), input: fc.record({ list: fc.string(), orderedIds: fc.string() }) }),
              fc.record({ action: fc.constant('nest'), input: fc.record({ list: fc.string(), parent: fc.string() }) }),
              fc.record({ action: fc.constant('setCollapsed'), input: fc.record({ list: fc.string(), collapsed: fc.boolean() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ list: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ list: fc.string() }) }),
              fc.record({ action: fc.constant('listForSchema'), input: fc.record({ schema: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = fieldItemListHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(fieldItemListHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphaned items in list', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ list: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), schema: fc.string() }) }),
              fc.record({ action: fc.constant('addItem'), input: fc.record({ list: fc.string(), placementId: fc.string({ minLength: 1, maxLength: 50 }), position: fc.string() }) }),
              fc.record({ action: fc.constant('removeItem'), input: fc.record({ list: fc.string(), placementId: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('reorder'), input: fc.record({ list: fc.string(), orderedIds: fc.string() }) }),
              fc.record({ action: fc.constant('nest'), input: fc.record({ list: fc.string(), parent: fc.string() }) }),
              fc.record({ action: fc.constant('setCollapsed'), input: fc.record({ list: fc.string(), collapsed: fc.boolean() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ list: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ list: fc.string() }) }),
              fc.record({ action: fc.constant('listForSchema'), input: fc.record({ schema: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = fieldItemListHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(fieldItemListHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: orphaned items in list
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

